const { ethers } = require('ethers');

const ABI = [
  'function exactInputSingle((address tokenIn, address tokenOut, uint24 fee, address recipient, uint256 deadline, uint256 amountIn, uint256 amountOutMinimum, uint160 sqrtPriceLimitX96) params) external'
];

const data = "";

const iface = new ethers.Interface(ABI);
const decoded = iface.parseTransaction({ data });

console.log(JSON.stringify(decoded.args[0].toObject(), (key, value) =>
  typeof value === 'bigint' ? value.toString() : value, 2));
